package com.example.demo.models;import jakarta.persistence.*;import lombok.*;import java.math.BigDecimal;import java.time.LocalDateTime;
@Entity @Table(name="movimientos_cuenta") @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder public class MovimientoCuenta{@Id @GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;@ManyToOne(fetch=FetchType.LAZY,optional=false)@JoinColumn(name="cliente_id")private Cliente cliente;@Column(nullable=false)private LocalDateTime fecha;@Enumerated(EnumType.STRING)@Column(nullable=false)private Tipo tipo;@Column(nullable=false,precision=14,scale=2)private BigDecimal monto;@Column(name="saldo_resultante",nullable=false,precision=14,scale=2)private BigDecimal saldoResultante;private String descripcion;@ManyToOne(fetch=FetchType.LAZY)@JoinColumn(name="venta_id")private Venta venta;@ManyToOne(fetch=FetchType.LAZY)@JoinColumn(name="usuario_id")private Persona usuario;public enum Tipo{VENTA_FIADA,PAGO,AJUSTE,DEVOLUCION}}
